import { describe, expect, it } from "vitest";
import { createLimiter } from "../src/limiter.js";

// Each test names the concrete bug it would catch. Expected values are
// computed by hand from the documented contract, not from the implementation.

describe("createLimiter — limit boundary (strictly less than)", () => {
  it("allows exactly `limit` calls in a fresh window", () => {
    // Bug: off-by-one that allows limit+1 or only limit-1 calls.
    const rl = createLimiter(3, 1000);
    expect(rl.allow("k", 0)).toBe(true); // 1st, recent count 0 < 3
    expect(rl.allow("k", 1)).toBe(true); // 2nd, count 1 < 3
    expect(rl.allow("k", 2)).toBe(true); // 3rd, count 2 < 3
  });

  it("denies the (limit+1)th call in the same window", () => {
    // Bug: using `<=` instead of `<` (strictly less than).
    const rl = createLimiter(3, 1000);
    rl.allow("k", 0);
    rl.allow("k", 1);
    rl.allow("k", 2);
    expect(rl.allow("k", 3)).toBe(false); // count 3, not < 3
  });

  it("defaults to a limit of 5", () => {
    // Bug: wrong default limit.
    const rl = createLimiter(); // limit=5, windowMs=60000
    for (let i = 0; i < 5; i++) {
      expect(rl.allow("k", i)).toBe(true);
    }
    expect(rl.allow("k", 5)).toBe(false); // 6th denied
  });

  it("allows a single call when limit is 1", () => {
    // Bug: window/limit logic breaking at the smallest limit.
    const rl = createLimiter(1, 1000);
    expect(rl.allow("k", 0)).toBe(true);
    expect(rl.allow("k", 1)).toBe(false);
  });
});

describe("createLimiter — window expiry boundary (t > now - windowMs)", () => {
  it("counts a call that is windowMs-1 old (just inside the window)", () => {
    // Bug: using `>=` for the lower bound would still count it, but a `>`
    // that is mistakenly `t >= now - windowMs + 1` etc. would drop it early.
    const rl = createLimiter(1, 1000);
    expect(rl.allow("k", 0)).toBe(true); // recorded at t=0
    // now=999 → now-windowMs = -1; t=0 > -1 → still counts → deny.
    expect(rl.allow("k", 999)).toBe(false);
  });

  it("expires a call that is exactly windowMs old (t === now - windowMs)", () => {
    // Bug: using `>=` instead of `>` would keep the boundary call and wrongly
    // deny here.
    const rl = createLimiter(1, 1000);
    expect(rl.allow("k", 0)).toBe(true); // recorded at t=0
    // now=1000 → now-windowMs = 0; t=0 > 0 is false → expired → allow.
    expect(rl.allow("k", 1000)).toBe(true);
  });

  it("expires a call that is windowMs+1 old (well outside the window)", () => {
    // Bug: never expiring old calls.
    const rl = createLimiter(1, 1000);
    expect(rl.allow("k", 0)).toBe(true);
    // now=1001 → now-windowMs = 1; t=0 > 1 false → expired → allow.
    expect(rl.allow("k", 1001)).toBe(true);
  });

  it("frees exactly one slot as the oldest call slides out of the window", () => {
    // Bug: expiring all history or none when the window advances.
    const rl = createLimiter(2, 100);
    expect(rl.allow("k", 0)).toBe(true); // [0]
    expect(rl.allow("k", 50)).toBe(true); // [0,50]
    expect(rl.allow("k", 60)).toBe(false); // both in window, 2 not < 2
    // now=100: t=0 expired (0 > 0 false), t=50 kept → count 1 < 2 → allow.
    expect(rl.allow("k", 100)).toBe(true); // [50,100]
    // now=100 again: count is now 2 (50,100) → deny.
    expect(rl.allow("k", 100)).toBe(false);
  });

  it("uses the default window of 60000ms", () => {
    // Bug: wrong default windowMs.
    const rl = createLimiter(1); // limit=1, windowMs=60000
    expect(rl.allow("k", 0)).toBe(true);
    expect(rl.allow("k", 59999)).toBe(false); // 0 > -1 → still counts
    expect(rl.allow("k", 60000)).toBe(true); // 0 > 0 false → expired
  });
});

describe("createLimiter — denied calls record nothing", () => {
  it("does not record a denied call, so it never consumes future capacity", () => {
    // Bug: recording the timestamp of a rejected call.
    const rl = createLimiter(1, 100);
    expect(rl.allow("k", 0)).toBe(true); // recorded [0]
    expect(rl.allow("k", 50)).toBe(false); // denied; must NOT record 50
    // now=101: t=0 expired (0 > 1 false). If 50 had been recorded it would
    // still be in-window (50 > 1) and deny. Expect allow → proves not recorded.
    expect(rl.allow("k", 101)).toBe(true);
  });
});

describe("createLimiter — independent buckets per key", () => {
  it("tracks each key's window separately", () => {
    // Bug: sharing one counter across all keys.
    const rl = createLimiter(1, 1000);
    expect(rl.allow("a", 0)).toBe(true);
    expect(rl.allow("b", 0)).toBe(true); // b has its own fresh budget
    expect(rl.allow("a", 1)).toBe(false); // a is now full
    expect(rl.allow("b", 1)).toBe(false); // b is independently full
  });

  it("exhausting one key does not deny another", () => {
    // Bug: a global limit leaking across keys.
    const rl = createLimiter(2, 1000);
    rl.allow("a", 0);
    rl.allow("a", 0);
    expect(rl.allow("a", 0)).toBe(false); // a exhausted
    expect(rl.allow("c", 0)).toBe(true); // c untouched
  });
});

describe("createLimiter — invalid `now` throws TypeError", () => {
  it("throws for NaN", () => {
    // Bug: NaN slipping through comparisons and corrupting the window.
    const rl = createLimiter();
    expect(() => rl.allow("k", NaN)).toThrow(TypeError);
  });

  it("throws for Infinity", () => {
    const rl = createLimiter();
    expect(() => rl.allow("k", Infinity)).toThrow(TypeError);
  });

  it("throws for -Infinity", () => {
    const rl = createLimiter();
    expect(() => rl.allow("k", -Infinity)).toThrow(TypeError);
  });

  it("throws for a numeric string", () => {
    // Bug: accepting "0" and coercing it.
    const rl = createLimiter();
    expect(() => rl.allow("k", "0")).toThrow(TypeError);
  });

  it("throws for undefined (missing timestamp)", () => {
    const rl = createLimiter();
    expect(() => rl.allow("k")).toThrow(TypeError);
  });

  it("throws for null", () => {
    const rl = createLimiter();
    expect(() => rl.allow("k", null)).toThrow(TypeError);
  });

  it("accepts 0 as a valid finite timestamp (no throw)", () => {
    // Bug: a falsy-check (`if (!now)`) rejecting the legitimate value 0.
    const rl = createLimiter();
    expect(rl.allow("k", 0)).toBe(true);
  });

  it("accepts negative finite timestamps", () => {
    // Bug: assuming timestamps are non-negative.
    const rl = createLimiter(1, 1000);
    expect(rl.allow("k", -500)).toBe(true);
    expect(rl.allow("k", -499)).toBe(false); // -500 > -1499 → still counts
  });
});

